"use strict";(self.webpackChunkPradocument=self.webpackChunkPradocument||[]).push([[5191],{6453:(n,s,a)=>{a.r(s),a.d(s,{data:()=>e});const e={key:"v-318b1f60",path:"/guide/js/%E5%AF%B9%E6%95%B0%E6%8D%AE%E5%A4%84%E7%90%86%E7%9A%845%E4%B8%AAAPI.html",title:"",lang:"en-US",frontmatter:{},excerpt:"",headers:[{level:2,title:"JavaScript 对数据处理的5个API",slug:"javascript-对数据处理的5个api",children:[]},{level:2,title:"向上取整： ceil",slug:"向上取整-ceil",children:[]},{level:2,title:"向下取整： floor",slug:"向下取整-floor",children:[]},{level:2,title:"四舍五入： round",slug:"四舍五入-round",children:[]},{level:2,title:"固定精度： toFixed",slug:"固定精度-tofixed",children:[]},{level:2,title:"固定长度： toPrecision",slug:"固定长度-toprecision",children:[]},{level:2,title:"取整： parseInt",slug:"取整-parseint",children:[]},{level:2,title:"取整： 位运算",slug:"取整-位运算",children:[]},{level:2,title:"这些位运算符在实现取整操作时，会表现出一些共同的特征：",slug:"这些位运算符在实现取整操作时-会表现出一些共同的特征",children:[]},{level:2,title:"对于其他类型，先使用 Number() 转换为数值类型，再进行位运算。",slug:"对于其他类型-先使用-number-转换为数值类型-再进行位运算。",children:[]},{level:2,title:"位运算能取整的原因是：",slug:"位运算能取整的原因是",children:[]}],filePathRelative:"guide/js/对数据处理的5个API.md",git:{updatedTime:1657620056e3,contributors:[{name:"孤城致幻",email:"Xast@123456",commits:1}]}}},144:(n,s,a)=>{a.r(s),a.d(s,{default:()=>t});const e=(0,a(6252).uE)('<h2 id="javascript-对数据处理的5个api" tabindex="-1"><a class="header-anchor" href="#javascript-对数据处理的5个api" aria-hidden="true">#</a> JavaScript 对数据处理的5个API</h2><p>在 JavaScript 中，对数值进行四舍五入操作的场景有以下几种：</p><ul><li>向上取整：ceil</li><li>向下取整：floor</li><li>四舍五入：round</li><li>固定精度：toFixed</li><li>固定长度：toPrecision</li><li>取整：parseInt、位运算</li></ul><h2 id="向上取整-ceil" tabindex="-1"><a class="header-anchor" href="#向上取整-ceil" aria-hidden="true">#</a> 向上取整： ceil</h2><p>ceil 是<code>天花板</code>的意思，表示在一个数值之上，且距离该数最近的整数。ceil 是 Math 对象的静态方法，需要传递一个参数，其调用方法如下：</p><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>Math<span class="token punctuation">.</span><span class="token function">ceil</span><span class="token punctuation">(</span><span class="token number">12.34</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">//13</span>\nMath<span class="token punctuation">.</span><span class="token function">ceil</span><span class="token punctuation">(</span><span class="token number">12.68</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">//13</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h2 id="向下取整-floor" tabindex="-1"><a class="header-anchor" href="#向下取整-floor" aria-hidden="true">#</a> 向下取整： floor</h2><p>floor 是<code>地板</code>的意思，表示在一个数值之下，且距离该数最近的整数。floor 是 Math 对象的静态方法，需要传递一个参数，其调用方法如下：</p><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>Math<span class="token punctuation">.</span><span class="token function">floor</span><span class="token punctuation">(</span><span class="token number">12.34</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 12</span>\nMath<span class="token punctuation">.</span><span class="token function">floor</span><span class="token punctuation">(</span><span class="token number">12.68</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 12</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h2 id="四舍五入-round" tabindex="-1"><a class="header-anchor" href="#四舍五入-round" aria-hidden="true">#</a> 四舍五入： round</h2><p>round 的作用是对一个浮点数进行四舍五入，并保留整数位。round 也是 Math 对象的静态方法，也需要传递一个参数，其调用方法如下：</p><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code>Math<span class="token punctuation">.</span><span class="token function">round</span><span class="token punctuation">(</span><span class="token number">12.34</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 12</span>\nMath<span class="token punctuation">.</span><span class="token function">round</span><span class="token punctuation">(</span><span class="token number">12.54</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 13</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h2 id="固定精度-tofixed" tabindex="-1"><a class="header-anchor" href="#固定精度-tofixed" aria-hidden="true">#</a> 固定精度： toFixed</h2><p>toFixed 和上面三个方法不同，它是 Number 原型上实现的一个方法，其作用是对一个浮点数进行四舍五入并保留固定小数位。 toFixed 需要传递一个参数，其调用方式如下：</p><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code><span class="token number">100.456001</span><span class="token punctuation">.</span><span class="token function">toFixed</span><span class="token punctuation">(</span><span class="token number">2</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 100.46</span>\n<span class="token number">100.456001</span><span class="token punctuation">.</span><span class="token function">toFixed</span><span class="token punctuation">(</span><span class="token number">3</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 100.456</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h2 id="固定长度-toprecision" tabindex="-1"><a class="header-anchor" href="#固定长度-toprecision" aria-hidden="true">#</a> 固定长度： toPrecision</h2><p>toPrecison 也是 Number 原型上实现的一个处理浮点数的方法，和 toFixed 不同的是，它是对一个浮点数进行四舍五入并保留固定长度的有效数字，包括整数部分。</p><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code><span class="token number">99.456001</span><span class="token punctuation">.</span><span class="token function">toPrecision</span><span class="token punctuation">(</span><span class="token number">5</span><span class="token punctuation">)</span><span class="token punctuation">;</span>  <span class="token comment">// 99.456</span>\n<span class="token number">100.456001</span><span class="token punctuation">.</span><span class="token function">toPrecision</span><span class="token punctuation">(</span><span class="token number">5</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 100.46</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h2 id="取整-parseint" tabindex="-1"><a class="header-anchor" href="#取整-parseint" aria-hidden="true">#</a> 取整： parseInt</h2><p>parseInt 是 全局对象 window上的一个方法，其作用是对一个可转换的数值取整，分为以下两种情况：</p><ol><li><p>将字符串数值转化为 Number 整数，对字符串的每一个字符进行转化，直到遇到不可转化的字符（包括小数点）停止。</p></li><li><p>对浮点类型数值取整，忽略小数部分，不做四舍五入处理</p></li></ol><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code><span class="token comment">// 字符串数值</span>\n<span class="token function">parseInt</span><span class="token punctuation">(</span><span class="token string">&#39;100&#39;</span><span class="token punctuation">)</span> <span class="token punctuation">;</span> <span class="token comment">// 100</span>\n<span class="token function">parseInt</span><span class="token punctuation">(</span><span class="token string">&#39;100axt&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 100</span>\n<span class="token function">parseInt</span><span class="token punctuation">(</span><span class="token string">&#39;100xh20&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 100</span>\n<span class="token function">parseInt</span><span class="token punctuation">(</span><span class="token string">&#39;100.78&#39;</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 123</span>\n<span class="token comment">// Number 类型</span>\n<span class="token function">parseInt</span><span class="token punctuation">(</span><span class="token number">100.12</span><span class="token punctuation">)</span> <span class="token punctuation">;</span> <span class="token comment">// 100</span>\n<span class="token function">parseInt</span><span class="token punctuation">(</span><span class="token number">100.78</span><span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">// 100</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br></div></div><h2 id="取整-位运算" tabindex="-1"><a class="header-anchor" href="#取整-位运算" aria-hidden="true">#</a> 取整： 位运算</h2><ul><li><code>| 0 ： 和 0 进行 按位或 操作，原值不变</code></li><li><code>~~ ： 两次 按位非 操作得到的也是原值</code></li><li><code>&gt;&gt; 0 ： 右移 0 位</code></li><li><code>&lt;&lt; 0 ： 左移 0 位</code></li><li><code>&gt;&gt;&gt; 0： 无符号右移 0 位</code></li></ul><h2 id="这些位运算符在实现取整操作时-会表现出一些共同的特征" tabindex="-1"><a class="header-anchor" href="#这些位运算符在实现取整操作时-会表现出一些共同的特征" aria-hidden="true">#</a> 这些位运算符在实现取整操作时，会表现出一些共同的特征：</h2><ul><li>对于 Number 类型来说，直接应用位操作， 和 parseInt 得到的结果几乎一样；</li><li>对于其他类型，内部会先通过 Number() 将其转换为一个数值，然后再应用位操作。</li><li>对特殊 NaN 和 Infinity 值应用位操作时，这两个值都会被当成 0 来处理 。</li><li>对于 Number 类型，直接应用位运算。</li></ul><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code><span class="token operator">~</span><span class="token operator">~</span> <span class="token number">100.12</span><span class="token punctuation">;</span>  <span class="token comment">//  100         </span>\n<span class="token number">100.78</span>  <span class="token operator">|</span>  <span class="token number">0</span><span class="token punctuation">;</span>    <span class="token comment">//  100    </span>\n<span class="token number">100.45</span> <span class="token operator">&gt;&gt;</span>  <span class="token number">0</span><span class="token punctuation">;</span>    <span class="token comment">//  100    </span>\n<span class="token number">100.50</span> <span class="token operator">&lt;&lt;</span>  <span class="token number">0</span><span class="token punctuation">;</span>   <span class="token comment">// 100      </span>\n<span class="token number">100.96</span> <span class="token operator">&gt;&gt;&gt;</span> <span class="token number">0</span><span class="token punctuation">;</span>    <span class="token comment">//  100    </span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><h2 id="对于其他类型-先使用-number-转换为数值类型-再进行位运算。" tabindex="-1"><a class="header-anchor" href="#对于其他类型-先使用-number-转换为数值类型-再进行位运算。" aria-hidden="true">#</a> 对于其他类型，先使用 Number() 转换为数值类型，再进行位运算。</h2><div class="language-javascript ext-js line-numbers-mode"><pre class="language-javascript"><code><span class="token operator">~</span><span class="token operator">~</span> <span class="token string">&#39;100.12&#39;</span>  <span class="token comment">// 100， Number(&#39;100.12&#39;) == 100.12</span>\n<span class="token string">&#39;100.50&#39;</span>  <span class="token operator">&gt;&gt;</span> <span class="token number">0</span><span class="token punctuation">;</span>  <span class="token comment">// 100，Number(&#39;100.50&#39;) == 100.50</span>\n<span class="token string">&#39;100.96&#39;</span>  <span class="token operator">&lt;&lt;</span> <span class="token number">0</span><span class="token punctuation">;</span>  <span class="token comment">// 100，Number(&#39;100.96&#39;) == 100.96</span>\n<span class="token operator">~</span><span class="token operator">~</span> <span class="token string">&#39;abc&#39;</span>  <span class="token comment">// 0 , Number(&#39;abc&#39;) == NaN</span>\n<span class="token string">&#39;12abc&#39;</span>  <span class="token operator">&gt;&gt;</span> <span class="token number">0</span><span class="token punctuation">;</span>  <span class="token comment">// 0, Number(&#39;12abc&#39;) == NaN</span>\n<span class="token keyword">undefined</span> <span class="token operator">|</span> <span class="token number">0</span> <span class="token punctuation">;</span> <span class="token comment">// 0, Number(undefined) == NaN</span>\n<span class="token operator">~</span><span class="token operator">~</span><span class="token keyword">null</span><span class="token punctuation">;</span>      <span class="token comment">// 0 , Number(null) == 0</span>\n<span class="token boolean">true</span> <span class="token operator">&gt;&gt;</span> <span class="token number">0</span><span class="token punctuation">;</span> <span class="token comment">// 1 , Number(true) == 1</span>\n<span class="token boolean">false</span> <span class="token operator">&gt;&gt;</span> <span class="token number">0</span><span class="token punctuation">;</span> <span class="token comment">//0 , Number(false) == 0</span>\n<span class="token punctuation">[</span><span class="token punctuation">]</span>  <span class="token operator">&lt;&lt;</span> <span class="token number">0</span><span class="token punctuation">;</span>     <span class="token comment">// 0 , Number([]) == 0</span>\n<span class="token operator">~</span><span class="token operator">~</span><span class="token number">NaN</span><span class="token punctuation">;</span> <span class="token comment">// 0</span>\n<span class="token number">Infinity</span> <span class="token operator">&gt;&gt;&gt;</span> <span class="token number">0</span><span class="token punctuation">;</span> <span class="token comment">// 0</span>\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><p>位运算作用于最基本的层次上，即按内存中表示数值的位来操作数值。</p><h2 id="位运算能取整的原因是" tabindex="-1"><a class="header-anchor" href="#位运算能取整的原因是" aria-hidden="true">#</a> 位运算能取整的原因是：</h2><p>ECMAScript 中的数值以64位双精度浮点数存储，但位运算只能作用于整数，因此要先将 64 位的浮点数转换成 32 位的整数，然后再进行位运算，最后再将计算结果转换成64位浮点数存储。</p>',32),p={},t=(0,a(3744).Z)(p,[["render",function(n,s){return e}]])},3744:(n,s)=>{s.Z=(n,s)=>{const a=n.__vccOpts||n;for(const[n,e]of s)a[n]=e;return a}}}]);